        discount_percent += 5
    discount = price * (discount_percent / 100)
    return max(price - discount, 0)

def test_no_membership_discount():
    assert calculate_discount(100, 10, False) == 90.0

def test_with_membership_discount():
    assert calculate_discount(100, 10, True) == 85.0

